 45	    override fun initSubscreen() {
 46	        // Configure background
 47	        mBackgroundImage = requirePreference<SwitchPreferenceCompat>("deckPickerBackground")
 48	        mBackgroundImage!!.onPreferenceClickListener = Preference.OnPreferenceClickListener {
 49	            if (mBackgroundImage!!.isChecked) {
 50	                try {
 51	                    mBackgroundImageResultLauncher.launch("image/*")
 52	                    mBackgroundImage!!.isChecked = true
 53	                } catch (ex: Exception) {
 54	                    Timber.e("%s", ex.localizedMessage)
 55	                }
 56	            } else {
 57	                mBackgroundImage!!.isChecked = false
 58	                val currentAnkiDroidDirectory = CollectionHelper.getCurrentAnkiDroidDirectory(requireContext())
 59	                val imgFile = File(currentAnkiDroidDirectory, "DeckPickerBackground.png")
 60	                if (imgFile.exists()) {
 61	                    if (imgFile.delete()) {
 62	                        showSnackbar(R.string.background_image_removed)
 63	                    } else {
 64	                        showSnackbar(R.string.error_deleting_image)
 65	                    }
 66	                } else {
 67	                    showSnackbar(R.string.background_image_removed)
 68	                }
 69	            }
 70	            true
 71	        }
 72	
 73	        val appThemePref = requirePreference<ListPreference>(R.string.app_theme_key)
 74	        val dayThemePref = requirePreference<ListPreference>(R.string.day_theme_key)
 75	        val nightThemePref = requirePreference<ListPreference>(R.string.night_theme_key)
 76	        val themeIsFollowSystem = appThemePref.value == Themes.FOLLOW_SYSTEM_MODE
 77	
 78	        // Remove follow system options in android versions which do not have system dark mode
 79	        // When minSdk reaches 29, the only necessary change is to remove this if-block
 80	        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.Q) {
 81	            dayThemePref.isVisible = false
 82	            nightThemePref.isVisible = false
 83	
 84	            // Drop "Follow system" option (the first one)
 85	            appThemePref.entries = resources.getStringArray(R.array.app_theme_labels).drop(1).toTypedArray()
 86	            appThemePref.entryValues = resources.getStringArray(R.array.app_theme_values).drop(1).toTypedArray()
 87	            if (themeIsFollowSystem) {
 88	                appThemePref.value = Theme.fallback.id
 89	            }
 90	        }
 91	        dayThemePref.isEnabled = themeIsFollowSystem
 92	        nightThemePref.isEnabled = themeIsFollowSystem
 93	
 94	        appThemePref.setOnPreferenceChangeListener { newValue ->
 95	            val selectedThemeIsFollowSystem = newValue == Themes.FOLLOW_SYSTEM_MODE
 96	            dayThemePref.isEnabled = selectedThemeIsFollowSystem
 97	            nightThemePref.isEnabled = selectedThemeIsFollowSystem
 98	
 99	            // Only restart if theme has changed
100	            if (newValue != appThemePref.value) {
101	                val previousThemeId = Themes.currentTheme.id
102	                appThemePref.value = newValue.toString()
103	                updateCurrentTheme(requireContext())
104	
105	                if (previousThemeId != Themes.currentTheme.id) {
106	                    ActivityCompat.recreate(requireActivity())
107	                }
108	            }
109	        }
110	
111	        dayThemePref.setOnPreferenceChangeListener { newValue ->
112	            if (newValue != dayThemePref.value && !systemIsInNightMode(requireContext()) && newValue != Themes.currentTheme.id) {
113	                ActivityCompat.recreate(requireActivity())
114	            }
115	        }
116	
117	        nightThemePref.setOnPreferenceChangeListener { newValue ->
118	            if (newValue != nightThemePref.value && systemIsInNightMode(requireContext()) && newValue != Themes.currentTheme.id) {
119	                ActivityCompat.recreate(requireActivity())
120	            }
121	        }
122	
123	        // Show estimate time
124	        // Represents the collection pref "estTime": i.e.
125	        // whether the buttons should indicate the duration of the interval if we click on them.
126	        requirePreference<SwitchPreferenceCompat>(R.string.show_estimates_preference).apply {
127	            launchCatchingTask { isChecked = withCol { config.get("estTimes") ?: true } }
128	            setOnPreferenceChangeListener { _, newETA ->
129	                val newETABool = newETA as? Boolean ?: return@setOnPreferenceChangeListener false
130	                launchCatchingTask { withCol { config.set("estTimes", newETABool) } }
131	                true
132	            }
133	        }
134	        // Show progress
135	        // Represents the collection pref "dueCounts": i.e.
136	        // whether the remaining number of cards should be shown.
137	        requirePreference<SwitchPreferenceCompat>(R.string.show_progress_preference).apply {
138	            launchCatchingTask { isChecked = withCol { config.get("dueCounts") ?: true } }
139	            setOnPreferenceChangeListener { _, newDueCountsValue ->
140	                val newDueCountsValueBool = newDueCountsValue as? Boolean ?: return@setOnPreferenceChangeListener false
141	                launchCatchingTask { withCol { config.set("dueCounts", newDueCountsValueBool) } }
142	                true
143	            }
144	        }
145	        // Show play buttons on cards with audio
146	        // Represents the collection pref "hideAudioPlayButtons":
147	        // hide_audio_play_buttons is the inverse of show
148	        requirePreference<SwitchPreferenceCompat>(R.string.show_audio_play_buttons_key).apply {
149	            launchCatchingTask { isChecked = withCol { !config.getBool(ConfigKey.Bool.HIDE_AUDIO_PLAY_BUTTONS) } }
150	            setOnPreferenceChangeListener { _, newValue ->
151	                val showPlayButtons = newValue as? Boolean ?: return@setOnPreferenceChangeListener false
152	                launchCatchingTask { withCol { config.setBool(ConfigKey.Bool.HIDE_AUDIO_PLAY_BUTTONS, !showPlayButtons) } }
153	                true
154	            }
155	        }
156	    }
157	
158	    private val mBackgroundImageResultLauncher = registerForActivityResult(ActivityResultContracts.GetContent()) { selectedImage ->
159	        if (selectedImage != null) {
160	            // handling file may result in exception
161	            try {
162	                val filePathColumn = arrayOf(MediaStore.MediaColumns.SIZE)
163	                requireContext().contentResolver.query(selectedImage, filePathColumn, null, null, null).use { cursor ->
164	                    cursor!!.moveToFirst()
165	                    // file size in MB
166	                    val fileLength = cursor.getLong(0) / (1024 * 1024)
167	                    val currentAnkiDroidDirectory = CollectionHelper.getCurrentAnkiDroidDirectory(requireContext())
168	                    val imageName = "DeckPickerBackground.png"
169	                    val destFile = File(currentAnkiDroidDirectory, imageName)
170	                    // Image size less than 10 MB copied to AnkiDroid directory
171	                    if (fileLength < 10) {
172	                        (requireContext().contentResolver.openInputStream(selectedImage) as FileInputStream).channel.use { sourceChannel ->
173	                            FileOutputStream(destFile).channel.use { destChannel ->
174	                                destChannel.transferFrom(sourceChannel, 0, sourceChannel.size())
